valueString.value:
define "TB screening algorithm Observation":
  [Observation: Concepts."TB screening algorithm"] O
    where O.status in { 'final', 'amended', 'corrected' }

/* End of Presumptive TB D.DE945 */

/*
@dataElement: HIV.D.DE956 - TB screening algorithm
@activity: HIV.D4 Screen for TB
@description: Screening algorithm selected for screening activities
*/
define "TB screening algorithm Observation":
  Elements."TB screening algorithm Observation" O
    where O.encounter.references(EncounterId)

/*
  @input: TB screening algorithm
  @pseudocode: "TB screening algorithm"='W4SS single screening algorithm'
  */
define "W4SS single screening algorithm":
  exists(
    Elements."TB screening algorithm Observation" O
      where O.value ~ Concepts."W4SS single screening algorithm"
  )

/**
 * HIV Elements
 */

// Auto-generated Elements from DAK Data Dictionary
//   Entries based on DAK Data Dictionary for Data Elements marked as used
//   in at least one Decision Support Table or Aggregate Indicator

/*
@dataElement: HIV.A.DE17 - Age
@activity: HIV.A6.1 Review sociodemographic data with client | HIV.A5 Create new client record
@description: Calculated age (number of years) of the client based on date of birth
*/
/** 
 * @dataElement Patient age in years
 */
define "Current Patient Age In Years":
  AgeInYearsAt(Today())

/*
 @input: Estimated age
 @pseudocode: "Estimated age" >= 10 years
 */
define "Age 10 or older":
  Elements."Current Patient Age In Years" >= 10

define "Symptoms of TB Observation":
  [Observation: Concepts."Symptoms of TB"] O
    where O.status in { 'final', 'amended', 'corrected' }

/* End of Other TB screening algorithm */

/*
@dataElement: HIV.D.DE973 - Symptoms of TB
@activity: HIV.D4 Screen for TB
@description: Symptoms that may indicate TB disease in clients living with HIV, based on a clinical algorithm
*/
define "Symptoms of TB Observation":
  Elements."Symptoms of TB Observation" O
    where O.encounter.references(EncounterId)

/*
 @input: Symptoms of TB
 @pseudocode: "Symptoms of TB" IN 'Current cough', 'Fever of 39 °C or greater', 'Weight loss (reported)', 'Night sweats'
 */
define "Has symptoms of TB":
  exists(
    Elements."Symptoms of TB Observation" O
      where O.value ~ Concepts."Current cough"
         or O.value ~ Concepts."Fever of 39 °C or greater"
         or O.value ~ Concepts."Weight loss reported"
         or O.value ~ Concepts."Night sweats"
  )

/*
 @input: Symptoms of TB
 @pseudocode: "Symptoms of TB" = 'None'
 */
define "Does not have symptoms of TB":
  exists(
    Elements."Symptoms of TB Observation" O
      where O.value ~ Concepts."None"
  ) or not("Has symptoms of TB")

/*
  @input: TB screening algorithm
  @pseudocode: "TB screening algorithm"='Sequential positive screening algorithm with W4SS and CRP'
  */
define "Sequential positive screening algorithm with W4SS and CRP":
  exists(
    Elements."TB screening algorithm Observation" O
      where O.value ~ Concepts."Sequential positive screening algorithm with W4SS and CRP"
  )

/* End of TB prevention services accepted */

/*
@dataElement: HIV.D.DE1026 - C reactive protein test result
@activity: HIV.D4 Screen for TB
@description: Test result of the client's C reactive protein test result in mg/L
*/
// TODO: Replace placeholder with relevant CQL logic
define "C reactive protein test result":
  [Observation: Concepts."C reactive protein test result"] O
    where O.status in { 'final', 'amended', 'corrected' }

/* End of TB prevention services accepted */

/*
@dataElement: HIV.D.DE1026 - C reactive protein test result
@activity: HIV.D4 Screen for TB
@description: Test result of the client's C reactive protein test result in mg/L
*/
define "C reactive protein test result":
  Elements."C reactive protein test result" O
    where O.encounter.references(EncounterId)

/*
 @input: C-reactive protein test result
 @pseudocode:
 */
define "No C-reactive protein test done":
  not(exists(
    Elements."C reactive protein test result"
  ))

/*
 @input: C-reactive protein test result
 @pseudocode: "C reactive protein test result" ≤ 5 mg/L
 */
define "C-reactive protein at or under 5mg/L":
  exists(
    Elements."C reactive protein test result" O
      where O.value < 5
  )

/*
 @input: C-reactive protein test result
 @pseudocode: "C reactive protein test result" > 5 mg/L
 */
define "C-reactive protein over 5mg/L":
  exists(
    Elements."C reactive protein test result" O
      where O.value > 5
  )

/*
  @input: TB screening algorithm
  @pseudocode: "TB screening algorithm"='Screening with any TB symptom'
  */
define "Screening with any TB symptom":
  exists(
    Elements."TB screening algorithm Observation" O
      where O.value ~ Concepts."Screening with any TB symptom"
  )

/*
 @input: Estimated age
 @pseudocode: "Estimated age" < 15 years
 */
define "Age under 15":
  Elements."Current Patient Age In Years" < 15

/* End of None */

/*
@dataElement: HIV.D.DE985 - History of contact with a person with TB
@activity: HIV.D4 Screen for TB
@description: Client had a history of a contact with a person with TB
*/
define "History of contact with a person with TB Observation":
  Elements."History of contact with a person with TB Observation" O
    where O.encounter.references(EncounterId)

/*
 @input: History of contact with a person with TB
 @pseudocode: "History of contact with a person with TB"=True
 */
define "History of contact with a person with TB":
  exists(
    Elements."History of contact with a person with TB Observation" O
      where O.value = true
  )

/*
@description: Returns true if the given reference is to the given resourceId
@comment: Returns true if the `resourceId` parameter exactly equals the tail of the given reference.
NOTE: This function assumes resources from the same source server.
*/
define fluent function references(reference FHIR.Reference, resourceId String):
  resourceId = Last(Split(reference.reference, '/'))
